sql:
SELECT COUNT(*)
FROM special_events
WHERE event_date BETWEEN '2022-01-01' AND '2022-12-31';

SELECT zone_name, location, manager_id
FROM zones
ORDER BY zone_capacity ASC;

SELECT DISTINCT m1.manager_name, m1.manager_department
FROM managers m1
JOIN managers m2 ON m1.manager_id = m2.manager_supervisor_id;

SELECT manager_department, COUNT(manager_id) AS num_managers
FROM managers
GROUP BY manager_department;

SELECT COUNT(*) AS TotalRecords
FROM zones
WHERE zone_id > 10;

SELECT AVG(actual_hire_count) AS average_bike_hires
FROM hire_data
WHERE zone_id = 'your_zone_id';

SELECT 
  (SELECT COUNT(*) FROM managers) AS total_managers,
  (SELECT COUNT(*) FROM users WHERE user_join_date >= date('now', '-1 month')) AS new_users_last_month;

SELECT z.zone_name, m.manager_name
FROM zones z
JOIN managers m ON z.manager_id = m.manager_id;

SELECT managers.manager_name, zones.zone_name
FROM managers
JOIN zones ON managers.manager_id = zones.manager_id;

SELECT COUNT(DISTINCT "zone_id") AS "Number of Zones with Temperature Above 28°C"
FROM "weather_data"
WHERE "temperature" > 28;

SELECT SUM(actual_hire_count)
FROM hire_data
WHERE zone_id = (SELECT zone_id FROM zones WHERE zone_name = 'Your Specific Zone Name');

SELECT event_location, COUNT(*) AS num_events
FROM special_events
GROUP BY event_location;

SELECT m1.manager_name, m2.manager_name AS supervisor_name
FROM managers m1
LEFT JOIN managers m2 ON m1.manager_supervisor_id = m2.manager_id;

SELECT COUNT(manager_id) 
FROM managers 
WHERE manager_supervisor_id IS NOT NULL;
